    jurisdiction: "slovenia",
    court: "VSC",
    court_level: "appellate",
    case_number: "VSC Sklep II Kp 84143/2022",
    decision_date: "2024-08-14",
    legal_area: "criminal",
    legal_question:
      "Da li je osnovan zahtjev radi bistvene kršitve določb kazenskega postopka ter zmotne in nepopolne ugotovitve dejanskega stanja. Pritožbenemu sodišču p?",
